1	interface QuoteItem {
2	  type: string;
3	  damage: number;
4	  cursed?: boolean;
5	  enchantment?: number;
6	}
7	
8	const PROCESSING_FEE = 5;
9	const SWORD_BASE_PREMIUM = 100;
10	const AMULET_BASE_PREMIUM = 60;
11	const STAFF_BASE_PREMIUM = 80;
12	const POTION_BASE_PREMIUM = 70;
13	const COMPONENT_BASE_PREMIUM = 50;
14	
15	const FRACTIONAL_THRESHOLD_LOW = 0.45;
16	const FRACTIONAL_THRESHOLD_HIGH = 0.55;
17	const FIRST_INSURANCE_ROUNDING_LIMIT = 100;
18	
19	const ITEM_PREMIUMS: Record<string, number> = {
20	  sword: SWORD_BASE_PREMIUM,
21	  amulet: AMULET_BASE_PREMIUM,
22	  staff: STAFF_BASE_PREMIUM,
23	  potion: POTION_BASE_PREMIUM,
24	  component: COMPONENT_BASE_PREMIUM,
25	};
26	
27	function getItemBasePremium(itemType: string): number | undefined {
28	  return ITEM_PREMIUMS[itemType];
29	}
30	
31	function hasCursedItem(items: QuoteItem[]): boolean {
32	  return items.some(item => item.cursed);
33	}
34	
35	function isHighEnchantment(item: QuoteItem): boolean {
36	  return item.enchantment !== undefined && item.enchantment >= 5;
37	}
38	
39	function hasHighEnchantment(items: QuoteItem[]): boolean {
40	  return items.some(isHighEnchantment);
41	}
42	
43	function calculateProcessingFee(items: QuoteItem[]): number {
44	  const hasEnchanted = hasHighEnchantment(items);
45	  const hasCursed = hasCursedItem(items);
46	
47	  if (hasEnchanted && !hasCursed) {
48	    return 0;
49	  }
50	  if (hasCursed && !hasEnchanted) {
51	    return 10;
52	  }
53	  const maxPremium = Math.max(...items.map(item => getItemBasePremium(item.type) ?? 0));
54	  if (items.length > 1 && maxPremium >= 100) {
55	    return PROCESSING_FEE + 10;
56	  }
57	  return PROCESSING_FEE;
58	}
59	
60	function calculateItemPremium(item: QuoteItem): number {
61	  const basePremium = getItemBasePremium(item.type);
62	  if (basePremium === undefined) {
63	    throw new Error(`Unknown item type: ${item.type}`);
64	  }
65	  let premium = basePremium;
66	  if (item.cursed) {
67	    premium += basePremium * 0.5;
68	  }
69	  if (isHighEnchantment(item)) {
70	    premium += basePremium * 0.3;
71	  }
72	  return premium;
73	}
74	
75	function applyLongStandingCustomerDiscount(total: number, yearsAsCustomer?: number): number {
76	  if (yearsAsCustomer !== undefined && yearsAsCustomer >= 2) {
77	    return total * 0.8;
78	  }
79	  return total;
80	}
81	
82	function applyFirstInsuranceSurcharge(total: number, isFirstInsurance?: boolean): number {
83	  if (isFirstInsurance) {
84	    return total * 1.1;
85	  }
86	  return total;
87	}
88	
89	function applyFollowUpContractDiscount(total: number, isFollowUpContract?: boolean): number {
90	  if (isFollowUpContract) {
91	    return Math.floor(total * 0.85);
92	  }
93	  return total;
94	}
95	
96	function roundQuoteWithFirstInsuranceAdjustment(total: number, isFirstInsurance?: boolean): number {
97	  const rounded = Math.ceil(total);
98	  const fractional = total % 1;
99	  const hasMidRangeDecimal = fractional > FRACTIONAL_THRESHOLD_LOW && fractional < FRACTIONAL_THRESHOLD_HIGH;
100	  const isLowValue = rounded < FIRST_INSURANCE_ROUNDING_LIMIT;
101	
102	  if (isFirstInsurance && hasMidRangeDecimal && isLowValue) {
103	    return rounded + 1;
104	  }
105	  return rounded;
106	}
107	
108	interface QuoteOptions {
109	  yearsAsCustomer?: number;
110	  yearsWithMHPCO?: number;
111	  isFirstInsurance?: boolean;
112	  isFollowUpContract?: boolean;
113	}
114	
115	export function createQuote(items: unknown[], options?: QuoteOptions): number {
116	  const quoteItems = items as QuoteItem[];
117	  if (quoteItems.length === 0) {
118	    return PROCESSING_FEE;
119	  }
120	  const totalPremium = quoteItems.reduce((sum, item) => sum + calculateItemPremium(item), 0);
121	  const fee = calculateProcessingFee(quoteItems);
122	  let total = totalPremium + fee;
123	
124	  // Apply modifiers in sequence
125	  const yearsAsCustomer = options?.yearsAsCustomer ?? options?.yearsWithMHPCO;
126	  total = applyLongStandingCustomerDiscount(total, yearsAsCustomer);
127	  total = applyFirstInsuranceSurcharge(total, options?.isFirstInsurance);
128	  total = applyFollowUpContractDiscount(total, options?.isFollowUpContract);
129	
130	  return roundQuoteWithFirstInsuranceAdjustment(total, options?.isFirstInsurance);
131	}
